#include<bits/stdc++.h>
using namespace std;
int main(){
	int n,a,b[10001],c=0;
	cin>>n>>a;
	for(int i=0;n!=0;i++){
		b[i]=n%a;
		n=n/a;
		c++;
	}for(int j=c-1;j!=-1;j--){
		if(b[j]<10){
			cout<<b[j];}
		else if(b[j]==10)cout<<"A";
		else if(b[j]==11)cout<<"B";
		else if(b[j]==12)cout<<"C";
		else if(b[j]==13)cout<<"D";
		else if(b[j]==14)cout<<"E";
		else if(b[j]==15)cout<<"F";
		else if(b[j]==16)cout<<"G";
		else if(b[j]==17)cout<<"H";
		else if(b[j]==18)cout<<"I";
		else if(b[j]==19)cout<<"J";
		else if(b[j]==20)cout<<"K";
		else if(b[j]==21)cout<<"L";
		else if(b[j]==22)cout<<"M";
		else if(b[j]==23)cout<<"N";
		else if(b[j]==24)cout<<"O";
		else if(b[j]==25)cout<<"P";
		else if(b[j]==26)cout<<"Q";
		else if(b[j]==27)cout<<"R";
		else if(b[j]==28)cout<<"S";
		else if(b[j]==29)cout<<"T";
		else if(b[j]==30)cout<<"U";
		else if(b[j]==31)cout<<"V";
		else if(b[j]==32)cout<<"W";
		else if(b[j]==33)cout<<"X";
		else if(b[j]==34)cout<<"Y";
		else if(b[j]==35)cout<<"Z";
	}
	return 0;
}
